fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let band1gaindb = required_f32(params, "band1gaindb").map_err(anyhow::Error::msg)?;
    let band2gaindb = required_f32(params, "band2gaindb").map_err(anyhow::Error::msg)?;
    let band3gaindb = required_f32(params, "band3gaindb").map_err(anyhow::Error::msg)?;
    let band4gaindb = required_f32(params, "band4gaindb").map_err(anyhow::Error::msg)?;
    let band5gaindb = required_f32(params, "band5gaindb").map_err(anyhow::Error::msg)?;
    let band6gaindb = required_f32(params, "band6gaindb").map_err(anyhow::Error::msg)?;
    let band7gaindb = required_f32(params, "band7gaindb").map_err(anyhow::Error::msg)?;
    let band8gaindb = required_f32(params, "band8gaindb").map_err(anyhow::Error::msg)?;
    let band1freqhz = required_f32(params, "band1freqhz").map_err(anyhow::Error::msg)?;
    let band2freqhz = required_f32(params, "band2freqhz").map_err(anyhow::Error::msg)?;
    let band3freqhz = required_f32(params, "band3freqhz").map_err(anyhow::Error::msg)?;
    let band4freqhz = required_f32(params, "band4freqhz").map_err(anyhow::Error::msg)?;
    let band5freqhz = required_f32(params, "band5freqhz").map_err(anyhow::Error::msg)?;
    let band6freqhz = required_f32(params, "band6freqhz").map_err(anyhow::Error::msg)?;
    let band7freqhz = required_f32(params, "band7freqhz").map_err(anyhow::Error::msg)?;
    let band8freqhz = required_f32(params, "band8freqhz").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BAND1_GAIN_DB, band1gaindb),
        (PORT_CTRL_BAND2_GAIN_DB, band2gaindb),
        (PORT_CTRL_BAND3_GAIN_DB, band3gaindb),
        (PORT_CTRL_BAND4_GAIN_DB, band4gaindb),
        (PORT_CTRL_BAND5_GAIN_DB, band5gaindb),
        (PORT_CTRL_BAND6_GAIN_DB, band6gaindb),
        (PORT_CTRL_BAND7_GAIN_DB, band7gaindb),
        (PORT_CTRL_BAND8_GAIN_DB, band8gaindb),
        (PORT_CTRL_BAND1_FREQ_HZ, band1freqhz),
        (PORT_CTRL_BAND2_FREQ_HZ, band2freqhz),
        (PORT_CTRL_BAND3_FREQ_HZ, band3freqhz),
        (PORT_CTRL_BAND4_FREQ_HZ, band4freqhz),
        (PORT_CTRL_BAND5_FREQ_HZ, band5freqhz),
        (PORT_CTRL_BAND6_FREQ_HZ, band6freqhz),
        (PORT_CTRL_BAND7_FREQ_HZ, band7freqhz),
        (PORT_CTRL_BAND8_FREQ_HZ, band8freqhz),
    ];

    match layout {
        AudioChannelLayout::Mono => {
            let processor = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_INPUT], &[PORT_AUDIO_OUT_OUTPUT], control_ports)?;
            Ok(BlockProcessor::Mono(Box::new(processor)))
        }
        AudioChannelLayout::Stereo => {
            let left = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_INPUT], &[PORT_AUDIO_OUT_OUTPUT], control_ports)?;
            let right = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_INPUT], &[PORT_AUDIO_OUT_OUTPUT], control_ports)?;
            Ok(BlockProcessor::Stereo(Box::new(DualMonoProcessor { left, right })))
        }
    }
}

struct DualMonoProcessor { left: lv2::Lv2Processor, right: lv2::Lv2Processor }
impl StereoProcessor for DualMonoProcessor {
    fn process_frame(&mut self, input: [f32; 2]) -> [f32; 2] {
        [self.left.process_sample(input[0]), self.right.process_sample(input[1])]
    }
}

